mapper.select:
SELECT EXISTS (
    SELECT 1
      FROM credit_transaction
     WHERE ai_usage_log_id = #{aiUsageLogId}
       AND type = #{type}
)

mapper.update:
UPDATE ai_usage_log
   SET credit_used = #{creditUsed}
 WHERE id = #{aiUsageLogId}

UPDATE users
   SET credit = credit - #{creditUsed}
 WHERE id = #{userId}
   AND credit >= #{creditUsed}

UPDATE users
   SET credit = credit + #{amount}
 WHERE id = #{userId}
   AND credit <= 2147483647 - #{amount}

mapper.select:
SELECT credit
  FROM users
 WHERE id = #{userId}
